VALUES
  ('fire-eq-tech-moex-01750', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據住宅用火災警報器認可基準，有關住宅用火災警報器構造與功能的規定，下列敘述何者錯誤？', '["應能確實動作且易於操作、附屬零件易於更換", "應具有易於安裝及更換之構造", "正常使用狀態下，不得因溫度變化導致外殼變形", "外部配線應能承受任何方向之100N拉力達1分鐘，且拉力不會傳遞到導線和電池端子連接器之接頭上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01751', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據火警自動警報設備測試報告書測試方法及判定要領，有關定溫式感知線型探測器之外觀試驗的規 定，下列敘述何者錯誤？', '["感知線應設置在裝置面下方0.1m以內之位置", "感知線之安裝在直線部分以每0.5m以內之間隔固定", "感知線之彎曲半徑應在0.05m以上", "感知線之接續，應使用端子接線"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01752', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據火警自動警報設備檢修及申報作業基準，探測器外觀檢查警戒狀況之判定方法的規定，有關性能障 礙下列敘述何者錯誤？', '["應無被塗漆", "火焰探測器應無日光直射等影響性能之顧慮", "光電式型探測器之受光部，應無日光直射等影響性能之顧慮", "應無因裝修造成妨礙熱氣流、煙流動之障礙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01753', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據緊急廣播設備檢修及申報作業基準，有關標示燈外觀檢查規定，標示燈與裝置面成P度角，在Q公 尺距離內應均能明顯易見。試問P與Q分別為何？', '["P＝10，Q＝15", "P＝10，Q＝7.5", "P＝15，Q＝10", "P＝15，Q＝7.5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01754', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據排煙設備檢修及申報作業基準，有關綜合檢查之判定方法的規定，下列敘述何者錯誤？', '["運轉電流在所規定的範圍內", "排煙機在運轉中應無異常聲音及振動，風道應無異常振動", "排煙機回轉葉片的回轉方向應正常", "排煙口及吸煙閘門打開後，能連動自動排煙機啟動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01755', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據避難器具檢修及申報作業基準，有關外觀檢查之判定方法的規定，下列敘述何者錯誤？', '["在操作面積內，除了輕量而容易移動之物品外，不得放置會妨礙之大型椅子、桌子、書架及其他物品等", "由地板面至開口部下端之高度應在80cm以下", "下降空地應有寬1公尺以上之避難上有效通路，通往廣場、道路等", "有電線時，應距離下降空間1.2m以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01756', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依據避難器具測試報告書測試方法及判定要領，有關避難器具設置場所等外觀試驗之判定要領的規定， 下列敘述何者錯誤？', '["應設置在容易接近，且無妨礙避難器具使用之空間，有安全構造之操作部", "應與設置在其他樓層之避難器具間相互無妨礙", "關於樓梯、出入口或其他相關避難設施之關連，應在適當之位置", "至樓地板面或其他著地點之下降空間，應無妨礙避難之障礙物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01757', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '緊急廣播設備之規定，下列何者錯誤？', '["啟動裝置於各樓層任一點至啟動裝置之步行距離應在50公尺以下", "特別安全梯應垂直距離每45公尺單獨設定一廣播分區", "樓梯至少垂直距離每20公尺應設1個Ｌ級揚聲器", "擴音機及操作裝置應具有選擇必要樓層或區域廣播之性能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01758', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '若一緊急昇降機間（未兼用）之排煙設備排煙閘門面積為 6m2，請問機械排煙時風速應為多少，方能符 合法令規定？', '["20m/min", "40m/min", "60m/min", "80m/min"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01759', 'fire-eq-tech', 'fire-eq-tech-moex-105-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某一場所第六層需設置排煙設備，並區分為三個排煙區劃，面積各自為450m2、400m2、400m2，試問其 排煙風量應至少為多少m3/min？', '["800", "900", "1000", "1200"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "909f79cc7b3b", "answer_pdf_sha1": "84d03e877089", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "402", "s": "0809", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
